    return (
        <div className="flex flex-col h-full">
            {/* Horizontal Tab Navigation */}
            <div className="flex items-center border-b border-gray-100 bg-white/50 px-2">
                {steps.map((step) => (
                    <button
                        key={step.id}
                        onClick={() => (step.id < currentStep || (step.id === 1 && uploadedImages.length > 0)) && setCurrentStep(step.id)}
                        disabled={step.id > currentStep && uploadedImages.length === 0}
                        className={`flex-1 py-4 text-center relative transition-colors ${
                            currentStep === step.id 
                                ? 'text-pink-600 font-bold' 
                                : step.id < currentStep 
                                    ? 'text-gray-600 hover:text-pink-500' 
                                    : 'text-gray-300 cursor-not-allowed'
                        }`}
                    >
                        <span className="text-xs md:text-sm uppercase tracking-wider block">{window.innerWidth < 640 ? step.short : step.name}</span>
                        {currentStep === step.id && (
                            <div className="absolute bottom-0 left-0 w-full h-0.5 bg-pink-500 rounded-t-full shadow-[0_-2px_10px_rgba(236,72,153,0.5)]"></div>
                        )}
                    </button>
                ))}
            </div>

            {/* Scrollable Content Area */}
            <div className="flex-grow overflow-y-auto p-6 space-y-8 custom-scrollbar">
                {currentStep === 1 && (
                    <div className="space-y-8 animate-fadeIn">
                         {/* Upload Section */}
                         <div className="space-y-3">
                            <div className="flex justify-between items-baseline">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Foto Produk Utama</label>
                                <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full ${uploadedImages.length > 0 ? 'bg-green-50 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                                    {uploadedImages.length}/10 Uploaded
                                </span>
                            </div>

                            {/* Upload Area */}
                            {uploadedImages.length < 10 && (
                                <div 
                                    className={`group relative border-2 border-dashed rounded-2xl p-8 text-center cursor-pointer transition-all duration-300 ${
                                        uploadedImages.length > 0
                                            ? 'border-gray-200 bg-gray-50/50 hover:border-pink-300 hover:bg-white'
                                            : 'border-pink-200 bg-pink-50/20' 
                                    }`}
                                    onDragOver={(e) => e.preventDefault()}
                                    onDrop={createDropHandler(onImageUpload)}
                                    onClick={() => fileInputRef.current?.click()}
                                >
                                    <input type="file" accept="image/*" multiple ref={fileInputRef} onChange={handleMultiImageUpload} className="hidden"/>
                                    <div className="py-2">
                                        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-3 shadow-sm border border-gray-100 group-hover:shadow-md group-hover:scale-110 transition-all">
                                            <Icon name="upload" className="w-6 h-6 text-pink-300 group-hover:text-pink-500 transition-colors"/>
                                        </div>
                                        <p className="text-sm font-semibold text-gray-600">
                                            {uploadedImages.length > 0 ? "Tambah gambar lagi" : "Klik untuk upload produk"}
                                        </p>
                                        <p className="text-xs text-gray-400 mt-1">Maksimal 10 gambar</p>
                                    </div>
                                </div>
                            )}

                            {/* Generation Mode Selector - Only visible when multiple images */}
                            {uploadedImages.length > 1 && (
                                <div className="bg-pink-50/50 border border-pink-100 rounded-xl p-3">
                                    <label className="text-[10px] font-bold text-pink-500 uppercase tracking-widest block mb-2">Mode Generasi</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        <button
                                            onClick={() => setGenerationMode('single')}
                                            className={`py-2 px-3 rounded-lg text-xs font-semibold transition-all flex items-center justify-center gap-2 ${
                                                generationMode === 'single'
                                                ? 'bg-pink-500 text-white shadow-md'
                                                : 'bg-white text-gray-600 hover:bg-pink-50'
                                            }`}
                                        >
                                            <span className="w-2 h-2 rounded-full bg-current opacity-50"></span>
                                            Fokus Produk Aktif (1)
                                        </button>
                                        <button
                                            onClick={() => setGenerationMode('group')}
                                            className={`py-2 px-3 rounded-lg text-xs font-semibold transition-all flex items-center justify-center gap-2 ${
                                                generationMode === 'group'
                                                ? 'bg-pink-500 text-white shadow-md'
                                                : 'bg-white text-gray-600 hover:bg-pink-50'
                                            }`}
                                        >
                                            <Icon name="preview" className="w-3 h-3 opacity-50"/>
                                            Foto Grup/Bundle (All)
                                        </button>
                                    </div>
                                    <p className="text-[10px] text-gray-500 mt-2 text-center">
                                        {generationMode === 'single' 
                                            ? 'Hanya memproses gambar yang dipilih (highlight) di bawah ini.'
                                            : 'Menggabungkan SEMUA gambar yang diupload menjadi satu komposisi flatlay/grup.'}
                                    </p>
                                </div>
                            )}

                            {/* Gallery Grid */}
                            {uploadedImages.length > 0 && (
                                <div className="grid grid-cols-3 sm:grid-cols-4 gap-3 mt-4">
                                    {uploadedImages.map((src, index) => (
                                        <div 
                                            key={index} 
                                            onClick={() => setActiveImageIndex(index)}
                                            className={`relative aspect-square rounded-xl overflow-hidden cursor-pointer group transition-all duration-200 border-2 ${
                                                activeImageIndex === index 
                                                    ? 'border-pink-500 ring-2 ring-pink-200 ring-offset-1 z-10' 
                                                    : generationMode === 'group' 
                                                        ? 'border-pink-200 ring-1 ring-pink-100 opacity-90' 
                                                        : 'border-gray-100 hover:border-pink-200 opacity-60 hover:opacity-100'
                                            }`}
                                        >
                                            <img src={src} alt={`Product ${index}`} className="w-full h-full object-cover" />
                                            {/* Remove Button */}
                                            <button
                                                onClick={(e) => { e.stopPropagation(); onRemoveUploadedImage(index); }}
                                                className="absolute top-1 right-1 bg-white/90 text-red-500 rounded-full w-6 h-6 flex items-center justify-center shadow-sm opacity-0 group-hover:opacity-100 hover:bg-red-50 transition-all"
                                                title="Remove"
                                            >
                                                <Icon name="close" className="w-3 h-3" />
                                            </button>
                                            {/* Active Indicator Label */}
                                            {activeImageIndex === index && generationMode === 'single' && (
                                                <div className="absolute bottom-0 inset-x-0 bg-pink-500/90 text-white text-[9px] font-bold text-center py-0.5">
                                                    ACTIVE
                                                </div>
                                            )}
                                            {generationMode === 'group' && (
                                                <div className="absolute top-1 left-1 bg-white/80 text-pink-600 rounded-full w-5 h-5 flex items-center justify-center text-[10px] font-bold shadow-sm">
                                                    {index + 1}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Description Section */}
                        <div className="space-y-3">
                            <div className="flex justify-between items-center">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Detail Produk</label>
                                {uploadedImages.length > 0 && (
                                    <button
                                        onClick={onGenerateAIDescription}
                                        disabled={isDescribingProduct}
                                        className="flex items-center gap-1 text-[10px] font-bold text-white bg-gradient-to-r from-pink-500 to-violet-500 px-3 py-1.5 rounded-full shadow-md shadow-pink-500/20 hover:opacity-90 transition-all disabled:opacity-50"
                                    >
                                        <Icon name="magic-wand" className="w-3 h-3" />
                                        AUTO DESCRIBE (ACTIVE IMG)
                                    </button>
                                )}
                            </div>
                            <div className="relative group">
                                <textarea
                                    value={productDescription}
                                    onChange={(e) => setProductDescription(e.target.value)}
                                    rows={3}
                                    className="w-full bg-gray-50 border-transparent rounded-xl px-4 py-3 text-sm focus:bg-white focus:ring-2 focus:ring-pink-200 focus:border-pink-300 transition-all placeholder-gray-400 resize-none shadow-inner"
                                    placeholder={isDescribingProduct ? "AI sedang menganalisis gambar..." : "Contoh: Botol minum estetik warna pastel pink, tutup kayu..."}
                                    disabled={isDescribingProduct}
                                />
                                <div className="absolute bottom-2 right-2 text-[10px] text-gray-300 pointer-events-none">
                                    {productDescription.length} chars
                                </div>
                            </div>
                        </div>

                        {/* Optional Model Upload */}
                        <div className="pt-6 border-t border-dashed border-gray-200">
                             <label className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase tracking-widest mb-4 cursor-pointer" onClick={() => document.getElementById('model-section')?.classList.toggle('hidden')}>
                                <span className="w-4 h-4 rounded bg-gray-200 flex items-center justify-center text-gray-600">+</span>
                                Opsi Lanjutan: Model Manusia
                             </label>

                             <div id="model-section" className={`${!modelImage ? '' : ''} space-y-4`}>
                                <div className="flex gap-4 items-start">
                                    <div 
                                        className="w-24 h-24 flex-shrink-0 border-2 border-dashed border-gray-300 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:border-pink-400 hover:bg-pink-50/30 transition-all"
                                        onClick={() => modelFileInputRef.current?.click()}
                                    >
                                        <input type="file" accept="image/*" ref={modelFileInputRef} onChange={createInputHandler(onModelImageUpload)} className="hidden"/>
                                        {modelImage ? (
                                            <div className="relative w-full h-full">
                                                <img src={modelImage} alt="Model" className="w-full h-full object-cover rounded-lg" />
                                                <button onClick={(e) => {e.stopPropagation(); onRemoveModelImage()}} className="absolute -top-2 -right-2 bg-gray-800 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs hover:bg-black"><Icon name="close" className="w-3 h-3"/></button>
                                            </div>
                                        ) : (
                                            <span className="text-[10px] text-gray-400 text-center px-1">Upload Model</span>
                                        )}
                                    </div>
                                    {modelImage && (
                                        <div className="flex-1">
                                            <label className="text-[10px] font-bold text-gray-400 uppercase mb-2 block">Interaksi</label>
                                            <div className="grid grid-cols-1 gap-2">
                                                {Object.entries(MODEL_INTERACTIONS).map(([key, {name, prompt}]) => (
                                                    <GridSelectOption 
                                                        key={key} 
                                                        label={name}
                                                        description={prompt}
                                                        isSelected={modelInteraction === key} 
                                                        onClick={() => setModelInteraction(key as ModelInteractionKey)}
                                                    />
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </div>
                             </div>
                        </div>
                    </div>
                )}

                {currentStep === 2 && (
                    <div className="space-y-8 animate-fadeIn">
                        {/* Background Mode Selector */}
                        <div className="flex p-1 bg-gray-100 rounded-xl w-full">
                            {[{key: 'theme', name: 'Pilih Tema'}, {key: 'upload', name: 'Upload Custom'}].map((mode) => (
                                <button
                                    key={mode.key}
                                    onClick={() => setBackgroundMode(mode.key as 'theme' | 'upload')}
                                    className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                                        backgroundMode === mode.key 
                                            ? 'bg-white text-gray-800 shadow-sm' 
                                            : 'text-gray-500 hover:text-gray-700'
                                    }`}
                                >
                                    {mode.name}
                                </button>
                            ))}
                        </div>

                        {backgroundMode === 'theme' ? (
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-4 block">Tema Aesthetic</label>
                                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                    {Object.entries(BACKGROUND_THEMES).map(([key, theme]) => (
                                        <ThemeCard
                                            key={key}
                                            theme={theme}
                                            isSelected={selectedTheme === key}
                                            onClick={() => setSelectedTheme(key as BackgroundThemeKey)}
                                        />
                                    ))}
                                </div>
                            </div>
                        ) : (
                            <div className="space-y-4">
                                <div 
                                    className="border-2 border-dashed border-gray-300 rounded-2xl p-8 text-center hover:border-pink-400 transition-all cursor-pointer"
                                    onClick={() => backgroundFileInputRef.current?.click()}
                                >
                                    <input type="file" accept="image/*" ref={backgroundFileInputRef} onChange={createInputHandler(onBackgroundImageUpload)} className="hidden"/>
                                    {backgroundImage ? (
                                        <div className="relative max-w-xs mx-auto">
                                            <img src={backgroundImage} className="rounded-lg shadow-md" />
                                            <button onClick={(e)=>{e.stopPropagation(); onRemoveBackgroundImage()}} className="absolute -top-2 -right-2 bg-white shadow-md p-1 rounded-full"><Icon name="close" className="w-4 h-4"/></button>
                                        </div>
                                    ) : (
                                        <p className="text-sm text-gray-500">Klik untuk upload background reference</p>
                                    )}
                                </div>
                                {backgroundImage && (
                                    <div className="bg-pink-50 p-4 rounded-xl border border-pink-100">
                                        <div className="flex items-center gap-2 text-pink-700 text-xs font-bold mb-2">
                                            <Icon name="magic-wand" className="w-3 h-3"/> AI Analysis
                                        </div>
                                        <p className="text-xs text-gray-600 italic">
                                            {isAnalyzingBackground ? "Menganalisis..." : (backgroundDescription || "Deskripsi akan muncul di sini.")}
                                        </p>
                                    </div>
                                )}
                            </div>
                        )}

                        <div className="grid grid-cols-1 gap-4">
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 block">Warna Dominan (Opsional)</label>
                                <input 
                                    type="text" 
                                    value={dominantColors} 
                                    onChange={(e) => setDominantColors(e.target.value)}
                                    className="w-full bg-gray-50 border-transparent rounded-xl px-4 py-2 text-sm focus:bg-white focus:ring-2 focus:ring-pink-200 transition-all"
                                    placeholder="e.g. sage green, soft lilac"
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 block">Properti Tambahan</label>
                                <input 
                                    type="text" 
                                    value={extraProps} 
                                    onChange={(e) => setExtraProps(e.target.value)}
                                    className="w-full bg-gray-50 border-transparent rounded-xl px-4 py-2 text-sm focus:bg-white focus:ring-2 focus:ring-pink-200 transition-all"
                                    placeholder="e.g. majalah fashion, cangkir kopi"
                                />
                            </div>
                        </div>
                    </div>
                )}

                {currentStep === 3 && (
                    <div className="space-y-8 animate-fadeIn">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {/* Composition */}
                            <div className="space-y-3">
                                <div className="flex items-center gap-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Komposisi</label>
                                    <InfoTooltip text="Seberapa dekat kamera dengan produk?" />
                                </div>
                                <div className="grid grid-cols-1 gap-2">
                                    {Object.entries(SHOT_COMPOSITIONS).map(([key, val]) => (
                                        <GridSelectOption 
                                            key={key}
                                            label={val.name}
                                            isSelected={shotComposition === key}
                                            onClick={() => setShotComposition(key as ShotCompositionKey)}
                                        />
                                    ))}
                                </div>
                            </div>

                            {/* Camera Angle */}
                            <div className="space-y-3">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest block">Sudut Kamera</label>
                                <div className="grid grid-cols-1 gap-2">
                                    {Object.entries(CAMERA_ANGLES).map(([key, val]) => (
                                        <GridSelectOption 
                                            key={key}
                                            label={val.name}
                                            isSelected={cameraAngle === key}
                                            onClick={() => setCameraAngle(key as CameraAngleKey)}
                                        />
                                    ))}
                                </div>
                            </div>
                        </div>

                        <div className="h-px bg-gray-100 w-full"></div>

                        {/* Lighting Style */}
                        <div className="space-y-3">
                             <div className="flex items-center gap-2">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Pencahayaan</label>
                                <InfoTooltip text="Menentukan mood dan atmosfer foto." />
                            </div>
                            <div className="grid grid-cols-3 gap-2">
                                {Object.entries(LIGHTING_STYLES).map(([key, val]) => (
                                    <button
                                        key={key}
                                        onClick={() => setLightStyle(key as LightStyleKey)}
                                        className={`px-2 py-3 rounded-xl text-xs font-medium transition-all border ${
                                            lightStyle === key 
                                                ? 'bg-pink-50 border-pink-300 text-pink-700 shadow-sm' 
                                                : 'bg-white border-gray-100 text-gray-600 hover:bg-gray-50'
                                        }`}
                                    >
                                        {val.name}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Hand Aesthetic (If no model) */}
                        {!modelImage && (
                            <div className="space-y-3">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest block">Human Touch</label>
                                <div className="flex flex-wrap gap-2">
                                    {Object.entries(AESTHETIC_HANDS).map(([key, val]) => (
                                        <button
                                            key={key}
                                            onClick={() => setAestheticHand(key as AestheticHandKey)}
                                            className={`px-3 py-2 rounded-full text-xs border transition-all ${
                                                aestheticHand === key 
                                                    ? 'bg-gray-800 text-white border-gray-800' 
                                                    : 'bg-white text-gray-600 border-gray-200 hover:border-gray-400'
                                            }`}
                                        >
                                            {val.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {currentStep === 4 && (
                    <div className="space-y-8 animate-fadeIn">
                        {/* Aspect Ratio */}
                        <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm">
                             <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3 block">Format Output</label>
                             <div className="grid grid-cols-3 gap-4">
                                {Object.entries(ASPECT_RATIOS).map(([key, val]) => (
                                    <button
                                        key={key}
                                        onClick={() => setAspectRatio(key as AspectRatioKey)}
                                        className={`flex flex-col items-center gap-2 p-2 rounded-lg transition-all ${
                                            aspectRatio === key ? 'bg-pink-50 ring-1 ring-pink-500' : 'hover:bg-gray-50'
                                        }`}
                                    >
                                        <div className={`border-2 rounded-sm ${aspectRatio === key ? 'border-pink-500 bg-white' : 'border-gray-300'}`} 
                                            style={{
                                                width: '20px', 
                                                height: key === '1:1' ? '20px' : key === '4:5' ? '25px' : '35px'
                                            }} 
                                        />
                                        <span className={`text-[10px] font-semibold ${aspectRatio === key ? 'text-pink-600' : 'text-gray-500'}`}>{val.name}</span>
                                    </button>
                                ))}
                             </div>
                        </div>

                        {/* Pastel Slider */}
                        <div className="space-y-2">
                            <div className="flex justify-between">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Intensitas Pastel</label>
                                <span className="text-xs font-mono text-pink-500 bg-pink-50 px-2 rounded">{pastelLevel}/5</span>
                            </div>
                            <input 
                                type="range" min="1" max="5" 
                                value={pastelLevel} 
                                onChange={(e) => setPastelLevel(parseInt(e.target.value))} 
                                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-pink-500"
                            />
                            <div className="flex justify-between text-[10px] text-gray-400">
                                <span>Natural</span>
                                <span>Dreamy</span>
                            </div>
                        </div>

                        {/* Quantity & Language */}
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 block">Jumlah</label>
                                <input type="number" min="1" max="4" value={numImages} onChange={(e) => setNumImages(parseInt(e.target.value))} className="w-full bg-gray-50 border-transparent rounded-xl px-3 py-2 text-sm focus:bg-white focus:ring-2 focus:ring-pink-200"/>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 block">Bahasa</label>
                                <select value={captionLanguage} onChange={(e) => setCaptionLanguage(e.target.value as CaptionLanguageKey)} className="w-full bg-gray-50 border-transparent rounded-xl px-3 py-2 text-sm focus:bg-white focus:ring-2 focus:ring-pink-200">
                                    {Object.entries(CAPTION_LANGUAGES).map(([key, name]) => (
                                        <option key={key} value={key}>{name}</option>
                                    ))}
                                </select>
                            </div>
                        </div>

                        {/* Checkboxes */}
                        <div className="space-y-3 pt-2">
                             <label className="flex items-center gap-3 p-3 bg-gray-50 rounded-xl cursor-pointer hover:bg-white hover:shadow-sm transition-all">
                                <input type="checkbox" checked={excludeText} onChange={(e) => setExcludeText(e.target.checked)} className="w-5 h-5 text-pink-500 border-gray-300 rounded focus:ring-pink-500"/>
                                <span className="text-sm text-gray-700 font-medium">Hapus teks/tulisan pada produk</span>
                            </label>

                            <div className="bg-gray-50 p-4 rounded-xl">
                                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3 block">Efek Magic</label>
                                <div className="space-y-2">
                                    {Object.entries(AI_DECORATIONS).map(([key, decoration]) => (
                                        <label key={key} className="flex items-center gap-3 cursor-pointer group">
                                            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${selectedDecorations.has(key as AiDecorationKey) ? 'bg-pink-500 border-pink-500 text-white' : 'bg-white border-gray-300'}`}>
                                                {selectedDecorations.has(key as AiDecorationKey) && <Icon name="check" className="w-3 h-3" />}
                                            </div>
                                            <input type="checkbox" className="hidden" checked={selectedDecorations.has(key as AiDecorationKey)} onChange={() => handleDecorationChange(key as AiDecorationKey)} />
                                            <span className="text-sm text-gray-700 group-hover:text-pink-600 transition-colors">{decoration.emoji} {decoration.name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Bottom Action Bar */}
            <div className="border-t border-gray-100 bg-white/80 backdrop-blur-md p-4 flex items-center gap-3">
                 {currentStep > 1 && (
                    <button
                        onClick={() => setCurrentStep(currentStep - 1)}
                        className="px-4 py-3 rounded-xl text-gray-500 hover:bg-gray-100 font-semibold transition-colors"
                    >
                        Back
                    </button>
                )}

                {currentStep < 4 ? (
                    <button
                        onClick={() => setCurrentStep(currentStep + 1)}
                        disabled={uploadedImages.length === 0}
                        className="flex-1 bg-gray-900 text-white font-bold py-3 px-6 rounded-xl hover:bg-black transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-gray-200"
                    >
                        Lanjut
                    </button>
                ) : (
                    <button
                        onClick={onGenerate}
                        disabled={isGenerating || uploadedImages.length === 0}
                        className="flex-1 relative overflow-hidden bg-gradient-to-r from-pink-500 to-violet-600 text-white font-bold py-3 px-6 rounded-xl transition-all shadow-lg shadow-pink-500/30 hover:shadow-pink-500/50 hover:scale-[1.01] disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        <span className="relative z-10 flex items-center justify-center gap-2">
                            {isGenerating ? <Icon name="spinner" className="animate-spin w-5 h-5"/> : <Icon name="magic-wand" className="w-5 h-5"/>}
                            {isGenerating ? 'Meracik Estetika...' : 'Generate Photos'}
                        </span>
                    </button>
                )}
            </div>
        </div>
    );
};

export default ControlPanel;
